const GROUP_FALLBACK = {"fridge":"🥬","freezer":"🧊","sauce":"🧂","room":"🥫"};

export function emojiFor(name, type) {
  const n = String(name || "");
  for (const [kw, e] of EMOJI_RULES) if (n.includes(kw)) return e;
  return GROUP_FALLBACK[type] || "🍽️";
}

const LOOKUP = {};
for (const [type, list] of Object.entries(INGREDIENT_DB)) {
  LOOKUP[type] = {};
  for (const it of list) LOOKUP[type][it.name] = it;
}

export function ingredientLookup(type, name) {
  return (LOOKUP[type] && LOOKUP[type][name]) || null;
}

// Auto category from name when an item is not in the DB.
export function autoCategory(type, name) {
  const hit = ingredientLookup(type, name);
  if (hit) return hit.category;
  const n = String(name || "");
  for (const it of (INGREDIENT_DB[type] || [])) {
    if (n && (n.includes(it.name) || it.name.includes(n))) return it.category;
  }
  const def = { fridge: "채소", freezer: "냉동간편식", sauce: "소스", room: "곡물" };
  return def[type] || "기본";
}

export const EN_NAME = {};
for (const list of Object.values(INGREDIENT_DB)) for (const it of list) EN_NAME[it.name] = it.en;
